from flask import Flask, request, jsonify
from functools import wraps
import secrets
import hashlib
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-in-production'

# In-memory storage (use a database in production)
users_db = {
    'admin': {
        'password_hash': hashlib.sha256('admin123'.encode()).hexdigest(),
        'name': 'Admin User'
    },
    'john': {
        'password_hash': hashlib.sha256('john123'.encode()).hexdigest(),
        'name': 'John Doe'
    }
}

# Token storage: token -> {username, created_at, expires_at}
active_tokens = {}


def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()


def generate_token():
    return secrets.token_hex(32)


def cleanup_expired_tokens():
    """Remove expired tokens from storage."""
    now = datetime.utcnow()
    expired = [token for token, data in active_tokens.items() if data['expires_at'] < now]
    for token in expired:
        del active_tokens[token]


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check for token in Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header:
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        # Also check query parameter as fallback
        if not token:
            token = request.args.get('token')

        if not token:
            return jsonify({
                'success': False,
                'message': 'Authentication token is missing. Provide it in the Authorization header as "Bearer <token>".'
            }), 401

        # Cleanup expired tokens
        cleanup_expired_tokens()

        # Validate token
        token_data = active_tokens.get(token)
        if not token_data:
            return jsonify({
                'success': False,
                'message': 'Token is invalid or has expired.'
            }), 401

        if token_data['expires_at'] < datetime.utcnow():
            del active_tokens[token]
            return jsonify({
                'success': False,
                'message': 'Token has expired. Please login again.'
            }), 401

        # Pass current user info to the decorated function
        request.current_user = {
            'username': token_data['username'],
            'name': users_db[token_data['username']]['name']
        }
        request.current_token = token

        return f(*args, **kwargs)
    return decorated


@app.route('/', methods=['GET'])
def home():
    return jsonify({
        'message': 'Welcome to the Flask Token Authentication API',
        'endpoints': {
            'POST /register': 'Register a new user (username, password, name)',
            'POST /login': 'Login and receive a token (username, password)',
            'POST /logout': 'Logout and invalidate token (requires token)',
            'GET /protected': 'Access protected resource (requires token)',
            'GET /profile': 'Get user profile (requires token)',
            'GET /users': 'List all users (requires token)',
        }
    })


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()

    if not data:
        return jsonify({'success': False, 'message': 'Request body must be JSON.'}), 400

    username = data.get('username')
    password = data.get('password')
    name = data.get('name', '')

    if not username or not password:
        return jsonify({'success': False, 'message': 'Username and password are required.'}), 400

    if len(username) < 3:
        return jsonify({'success': False, 'message': 'Username must be at least 3 characters.'}), 400

    if len(password) < 6:
        return jsonify({'success': False, 'message': 'Password must be at least 6 characters.'}), 400

    if username in users_db:
        return jsonify({'success': False, 'message': 'Username already exists.'}), 409

    users_db[username] = {
        'password_hash': hash_password(password),
        'name': name or username
    }

    return jsonify({
        'success': True,
        'message': f'User "{username}" registered successfully.',
        'user': {
            'username': username,
            'name': name or username
        }
    }), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()

    if not data:
        return jsonify({'success': False, 'message': 'Request body must be JSON.'}), 400

    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({'success': False, 'message': 'Username and password are required.'}), 400

    user = users_db.get(username)
    if not user or user['password_hash'] != hash_password(password):
        return jsonify({'success': False, 'message': 'Invalid username or password.'}), 401

    # Cleanup expired tokens
    cleanup_expired_tokens()

    # Generate a new token
    token = generate_token()
    expires_at = datetime.utcnow() + timedelta(hours=1)

    active_tokens[token] = {
        'username': username,
        'created_at': datetime.utcnow(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'message': 'Login successful.',
        'token': token,
        'expires_at': expires_at.isoformat() + 'Z',
        'user': {
            'username': username,
            'name': user['name']
        }
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout():
    token = request.current_token
    if token in active_tokens:
        del active_tokens[token]

    return jsonify({
        'success': True,
        'message': 'Logged out successfully. Token has been invalidated.'
    }), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({
        'success': True,
        'message': 'You have accessed a protected endpoint!',
        'user': request.current_user,
        'data': {
            'secret_info': 'This is protected data only visible to authenticated users.',
            'timestamp': datetime.utcnow().isoformat() + 'Z'
        }
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile():
    username = request.current_user['username']
    user = users_db.get(username)

    # Count active tokens for this user
    user_tokens = sum(
        1 for t_data in active_tokens.values()
        if t_data['username'] == username
    )

    return jsonify({
        'success': True,
        'profile': {
            'username': username,
            'name': user['name'],
            'active_sessions': user_tokens
        }
    }), 200


@app.route('/users', methods=['GET'])
@token_required
def list_users():
    users_list = [
        {'username': uname, 'name': udata['name']}
        for uname, udata in users_db.items()
    ]

    return jsonify({
        'success': True,
        'total_users': len(users_list),
        'users': users_list
    }), 200


@app.route('/refresh', methods=['POST'])
@token_required
def refresh_token():
    """Refresh the current token - invalidate old one and issue a new one."""
    old_token = request.current_token
    username = request.current_user['username']

    # Remove old token
    if old_token in active_tokens:
        del active_tokens[old_token]

    # Generate new token
    new_token = generate_token()
    expires_at = datetime.utcnow() + timedelta(hours=1)

    active_tokens[new_token] = {
        'username': username,
        'created_at': datetime.utcnow(),
        'expires_at': expires_at
    }

    return jsonify({
        'success': True,
        'message': 'Token refreshed successfully.',
        'token': new_token,
        'expires_at': expires_at.isoformat() + 'Z'
    }), 200


# Error handlers
